const clima = $json;
const finca = $('PostgreSQL — Obtener fincas con coordenadas').item.json;

if (!clima.hourly || clima.hourly.time.length === 0) {
  return [{ json: { skip: true, razon: 'Sin datos horarios' } }];
}

// Tomar primeras 4 horas (12h)
const periodos = clima.hourly.time.slice(0, 4).map((time, index) => ({
    tiempo: time,
    probLluvia: clima.hourly.precipitation_probability[index],
    lluvia_mm: clima.hourly.rain[index]
}));

const maxLluvia = Math.max(...periodos.map(p => p.probLluvia));
const precipTotal = periodos.reduce((sum, p) => sum + p.lluvia_mm, 0);
const hayLluvia = maxLluvia >= 80;
const lluviaModerada = maxLluvia >= 40 && maxLluvia < 80;

const recomendacion = hayLluvia
  ? 'NO_REGAR — Lluvia prevista (>' + Math.round(maxLluvia) + '% probabilidad)'
  : lluviaModerada
  ? 'REGAR_POCO — Lluvia moderada posible (' + Math.round(maxLluvia) + '%)'
  : 'REGAR_NORMAL — Sin lluvia prevista';

// --- Generar título dinámico y bloque de ahorro ---
const titulo_riego = hayLluvia ? '✅ Suspender riego hoy' : '💧 Recomendación de riego';

let html_ahorro = '';
if (hayLluvia) {
  const ahorro = precipTotal.toFixed(1);
  html_ahorro = `<p style="margin: 12px 0 0; font-size: 13px; color: #15803d;">💰 Ahorro estimado: ${ahorro} mm de agua</p>`;
}

return [{
  json: {
    finca_id: finca.finca_id,
    finca_nombre: finca.finca_nombre,
    municipio: finca.municipio,
    departamento: finca.departamento,
    email_propietario: finca.email_propietario,
    nombre_propietario: finca.nombre_propietario,
    probabilidad_lluvia: Math.round(maxLluvia),
    precipitacion_esperada_mm: Math.round(precipTotal * 10) / 10,
    temperatura_promedio: null,
    descripcion_clima: "Pronóstico Open-Meteo",
    hay_lluvia: hayLluvia,
    lluvia_moderada: lluviaModerada,
    recomendacion_riego: recomendacion,
    ahorro_estimado_mm: hayLluvia ? precipTotal.toFixed(1) : '0',
    titulo_riego: titulo_riego,
    html_ahorro: html_ahorro,
    skip: false
  }
}];

